@startuml
skinparam classAttributeIconSize 0

class "ConcreteDecorateA" <<C>> {
    + addState() : void;
}

class ConcreteComponent <<C>> {
    - operation();
}

interface Component <<I>> {
    o operation(): string;
}

abstract Decorator implements Component {
    # component: IComponent;

    ~operation(): string = this.component.operation();
}

